import java.io.*;import java.util.*;class Main{static int bfs(int[][] f,int sr,int sc,int tr,int tc){if(sr==tr&&sc==tc)return 0;int m=f.length,n=f[0].length;ArrayDeque<int[]> q=new ArrayDeque<>();boolean[][] seen=new boolean[m][n];q.offer(new int[]{sr,sc,0});seen[sr][sc]=true;while(!q.isEmpty()){int[] cur=q.poll();for(int[] d:new int[][]{{1,0},{-1,0},{0,1},{0,-1}}){int nr=cur[0]+d[0],nc=cur[1]+d[1];if(0<=nr&&nr<m&&0<=nc&&nc<n&&f[nr][nc]!=0&&!seen[nr][nc]){if(nr==tr&&nc==tc)return cur[2]+1;seen[nr][nc]=true;q.offer(new int[]{nr,nc,cur[2]+1});}}}return -1;}static int solve(int[][] f){ArrayList<int[]> trees=new ArrayList<>();for(int i=0;i<f.length;i++)for(int j=0;j<f[0].length;j++)if(f[i][j]>1)trees.add(new int[]{f[i][j],i,j});trees.sort(Comparator.comparingInt(a->a[0]));int sr=0,sc=0,total=0;for(int[] t:trees){int d=bfs(f,sr,sc,t[1],t[2]);if(d<0)return -1;total+=d;sr=t[1];sc=t[2];}return total;}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int m=Integer.parseInt(d[idx++]),n=Integer.parseInt(d[idx++]);int[][] f=new int[m][n];for(int i=0;i<m;i++)for(int j=0;j<n;j++)f[i][j]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(solve(f));}System.out.print(out);}}
